"""Additional agent tests for compute_largest_cc_size."""


def make_test_result(passed, expected=None, actual=None):
    """Match the custom tuple interface used by the grader."""
    return (passed, expected, actual)


def test_self_loop_component(module):
    """A self-loop should still count as a single-node component."""
    g = {0: {0}, 1: set(), 2: {3}, 3: {2}}
    result = module.compute_largest_cc_size(g)
    expected = 2
    return make_test_result(result == expected, expected, result)


def test_string_labeled_nodes(module):
    """Node labels should be treated opaquely."""
    g = {
        "a": {"b"},
        "b": {"a", "c"},
        "c": {"b"},
        "x": set(),
    }
    result = module.compute_largest_cc_size(g)
    expected = 3
    return make_test_result(result == expected, expected, result)


def test_empty_neighbor_sets_with_sparse_ids(module):
    """Sparse labels and isolated nodes should not affect correctness."""
    g = {10: set(), 25: {40}, 40: {25}, 1000: set()}
    result = module.compute_largest_cc_size(g)
    expected = 2
    return make_test_result(result == expected, expected, result)
